import React, { useState } from 'react';
import LeagueSetupStep1 from './components/LeagueSetupStep1';

function App() {
  const [step, setStep] = useState(1);
  const [leagueSettings, setLeagueSettings] = useState(null);

  const handleStep1Next = (settings) => {
    setLeagueSettings(settings);
    setStep(2);
    // Step 2 (Player Entry) will be added next
    console.log('League settings saved:', settings);
  };

  return (
    <div className="app">
      {step === 1 && (
        <LeagueSetupStep1 onNext={handleStep1Next} />
      )}
      {step === 2 && (
        <div style={{ color: 'var(--cream)', fontFamily: 'DM Sans, sans-serif', textAlign: 'center', marginTop: '4rem' }}>
          <h2>Step 2: Player Entry — Coming Soon</h2>
          <p style={{ marginTop: '1rem', color: 'var(--muted)' }}>Settings saved: {leagueSettings?.leagueName}</p>
          <button
            onClick={() => setStep(1)}
            style={{ marginTop: '1.5rem', background: 'none', border: '1px solid var(--lime)', color: 'var(--lime)', padding: '0.5rem 1.2rem', cursor: 'pointer', borderRadius: '2px' }}
          >
            ← Back
          </button>
        </div>
      )}
    </div>
  );
}

export default App;
